import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { buildNamedRegionMap, getNamedRegions, NamedRegion } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

function assertRegions(lines: string[], expected: NamedRegion[]): void {
	const model = createTextModel(lines.join('\n'));
	const actual = getNamedRegions(model);
	assert.deepStrictEqual(actual, expected);
	model.dispose();
}

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('detects a simple named region', () => {
		assertRegions([
			/* 1 */ '// #region MySection',
			/* 2 */ 'const x = 1;',
			/* 3 */ '// #endregion',
		], [
			{ name: 'MySection', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('detects a region without comment prefix', () => {
		assertRegions([
			/* 1 */ '#region DataLayer',
			/* 2 */ 'function fetchData() {}',
			/* 3 */ '#endregion',
		], [
			{ name: 'DataLayer', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('extracts name with leading and trailing whitespace trimmed', () => {
		assertRegions([
			/* 1 */ '// #region   Trimmed Name   ',
			/* 2 */ 'let y = 2;',
			/* 3 */ '// #endregion',
		], [
			{ name: 'Trimmed Name', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('returns empty array when no named regions are present', () => {
		assertRegions([
			'const a = 1;',
			'const b = 2;',
		], []);
	});

	test('ignores unnamed #region markers', () => {
		assertRegions([
			/* 1 */ '// #region',
			/* 2 */ 'const z = 3;',
			/* 3 */ '// #endregion',
		], []);
	});

	test('handles multiple non-nested regions', () => {
		assertRegions([
			/* 1 */ '// #region Alpha',
			/* 2 */ 'let a = 1;',
			/* 3 */ '// #endregion',
			/* 4 */ '// #region Beta',
			/* 5 */ 'let b = 2;',
			/* 6 */ '// #endregion',
		], [
			{ name: 'Alpha', startLineNumber: 1, endLineNumber: 3 },
			{ name: 'Beta', startLineNumber: 4, endLineNumber: 6 },
		]);
	});

	test('handles nested regions', () => {
		assertRegions([
			/* 1 */ '// #region Outer',
			/* 2 */ '  // #region Inner',
			/* 3 */ '  const x = 1;',
			/* 4 */ '  // #endregion',
			/* 5 */ '// #endregion',
		], [
			{ name: 'Outer', startLineNumber: 1, endLineNumber: 5 },
			{ name: 'Inner', startLineNumber: 2, endLineNumber: 4 },
		]);
	});

	test('ignores unmatched #endregion', () => {
		assertRegions([
			/* 1 */ '// #endregion',
			/* 2 */ 'const x = 1;',
		], []);
	});

	test('ignores unmatched #region (no closing tag)', () => {
		assertRegions([
			/* 1 */ '// #region Unclosed',
			/* 2 */ 'const x = 1;',
		], []);
	});

	test('handles mixed indented region markers', () => {
		assertRegions([
			/* 1 */ 'class Foo {',
			/* 2 */ '    // #region PublicAPI',
			/* 3 */ '    method() {}',
			/* 4 */ '    // #endregion',
			/* 5 */ '}',
		], [
			{ name: 'PublicAPI', startLineNumber: 2, endLineNumber: 4 },
		]);
	});

	test('returns regions sorted by start line', () => {
		// This tests that the sort is stable regardless of stack pop order
		assertRegions([
			/* 1 */ '// #region First',
			/* 2 */ '// #region Second',
			/* 3 */ '// #endregion',
			/* 4 */ '// #endregion',
		], [
			{ name: 'First', startLineNumber: 1, endLineNumber: 4 },
			{ name: 'Second', startLineNumber: 2, endLineNumber: 3 },
		]);
	});
});

suite('buildNamedRegionMap', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('builds a map from region names to NamedRegion', () => {
		const regions: NamedRegion[] = [
			{ name: 'Alpha', startLineNumber: 1, endLineNumber: 5 },
			{ name: 'Beta', startLineNumber: 6, endLineNumber: 10 },
		];
		const map = buildNamedRegionMap(regions);
		assert.strictEqual(map.size, 2);
		assert.deepStrictEqual(map.get('Alpha'), regions[0]);
		assert.deepStrictEqual(map.get('Beta'), regions[1]);
	});

	test('first region wins when names collide', () => {
		const regions: NamedRegion[] = [
			{ name: 'Dup', startLineNumber: 1, endLineNumber: 3 },
			{ name: 'Dup', startLineNumber: 5, endLineNumber: 8 },
		];
		const map = buildNamedRegionMap(regions);
		assert.strictEqual(map.size, 1);
		assert.deepStrictEqual(map.get('Dup'), regions[0]);
	});

	test('returns empty map for empty input', () => {
		const map = buildNamedRegionMap([]);
		assert.strictEqual(map.size, 0);
	});

	test('can look up a region and get its line range', () => {
		const model = createTextModel([
			'// #region Setup',
			'const db = connect();',
			'// #endregion',
			'// #region Teardown',
			'db.close();',
			'// #endregion',
		].join('\n'));

		const regions = getNamedRegions(model);
		const map = buildNamedRegionMap(regions);

		assert.ok(map.has('Setup'));
		assert.ok(map.has('Teardown'));

		const setup = map.get('Setup')!;
		assert.strictEqual(setup.startLineNumber, 1);
		assert.strictEqual(setup.endLineNumber, 3);

		const teardown = map.get('Teardown')!;
		assert.strictEqual(teardown.startLineNumber, 4);
		assert.strictEqual(teardown.endLineNumber, 6);

		model.dispose();
	});
});

