396: 
397: 	constructor(private readonly ranges: FoldingRegions, private index: number) {
398: 	}
399: 
400: 	public get startLineNumber() {
401: 		return this.ranges.getStartLineNumber(this.index);
402: 	}
403: 
404: 	public get endLineNumber() {
405: 		return this.ranges.getEndLineNumber(this.index);
406: 	}
407: 
408: 	public get regionIndex() {
409: 		return this.index;
410: 	}
411: 
412: 	public get parentIndex() {
413: 		return this.ranges.getParentIndex(this.index);
414: 	}
415: 
416: 	public get isCollapsed() {
417: 		return this.ranges.isCollapsed(this.index);
418: 	}
419: 
420: 	containedBy(range: ILineRange): boolean {
421: 		return range.startLineNumber <= this.startLineNumber && range.endLineNumber >= this.endLineNumber;
422: 	}
423: 	containsLine(lineNumber: number) {
424: 		return this.startLineNumber <= lineNumber && lineNumber <= this.endLineNumber;
425: 	}
426: 	hidesLine(lineNumber: number) {
427: 		return this.startLineNumber < lineNumber && lineNumber <= this.endLineNumber;
428: 	}
