53: 		const model = createTextModel(lines.join('\n'));
54: 
55: 		function assertLimit(maxEntries: number, expectedRanges: IndentRange[], message: string) {
56: 			let reported: number | false = false;
57: 			const indentRanges = computeRanges(model, true, undefined, { limit: maxEntries, update: (computed, limited) => reported = limited });
58: 			assert.ok(indentRanges.length <= maxEntries, 'max ' + message);
59: 			const actual: IndentRange[] = [];
60: 			for (let i = 0; i < indentRanges.length; i++) {
61: 				actual.push({ start: indentRanges.getStartLineNumber(i), end: indentRanges.getEndLineNumber(i) });
62: 			}
63: 			assert.deepStrictEqual(actual, expectedRanges, message);
64: 			assert.equal(reported, 9 <= maxEntries ? false : maxEntries, 'limited');
65: 		}
