188: 	/**
189: 	 * Store view state.
190: 	 */
191: 	public saveViewState(): FoldingStateMemento | undefined {
192: 		const model = this.editor.getModel();
193: 		if (!model || !this._isEnabled || model.isTooLargeForTokenization()) {
194: 			return {};
195: 		}
196: 		if (this.foldingModel) { // disposed ?
197: 			const collapsedRegions = this.foldingModel.getMemento();
198: 			const provider = this.rangeProvider ? this.rangeProvider.id : undefined;
199: 			return { collapsedRegions, lineCount: model.getLineCount(), provider, foldedImports: this._currentModelHasFoldedImports };
200: 		}
201: 		return undefined;
202: 	}
203: 
204: 	/**
205: 	 * Restore view state.
206: 	 */
207: 	public restoreViewState(state: FoldingStateMemento): void {
208: 		const model = this.editor.getModel();
209: 		if (!model || !this._isEnabled || model.isTooLargeForTokenization() || !this.hiddenRangeModel) {
210: 			return;
211: 		}
212: 		if (!state) {
213: 			return;
214: 		}
215: 
216: 		this._currentModelHasFoldedImports = !!state.foldedImports;
217: 		if (state.collapsedRegions && state.collapsedRegions.length > 0 && this.foldingModel) {
218: 			this._restoringViewState = true;
219: 			try {
220: 				this.foldingModel.applyMemento(state.collapsedRegions);
221: 			} finally {
222: 				this._restoringViewState = false;
223: 			}
224: 		}
225: 	}
